127	    /// Build the BasicWorker instance
128	    pub fn build(self) -> BasicWorker {
129	        use std::sync::{
130	            atomic::{AtomicBool, AtomicUsize},
131	            Arc, RwLock as StdRwLock,
132	        };
133	
134	        use tokio::sync::OnceCell;
135	
136	        let bootstrap_host = parse_bootstrap_host_from_url(&self.url);
137	
138	        let bootstrap_port = match self.worker_type {
139	            WorkerType::Prefill { bootstrap_port } => bootstrap_port,
140	            _ => None,
141	        };
142	
143	        let metadata = WorkerMetadata {
144	            url: self.url.clone(),
145	            api_key: self.api_key,
146	            worker_type: self.worker_type,
147	            connection_mode: self.connection_mode,
148	            runtime_type: self.runtime_type,
149	            labels: self.labels,
150	            health_config: self.health_config,
151	            bootstrap_host,
152	            bootstrap_port,
153	            models: self.models,                // Empty = accepts any model
154	            default_provider: None,             // Native/passthrough
155	            default_model_type: ModelType::LLM, // Standard LLM capabilities
156	        };
157	
158	        // Use OnceCell for lock-free gRPC client access after initialization
159	        let grpc_client = Arc::new(match self.grpc_client {
160	            Some(client) => {
161	                let cell = OnceCell::new();
162	                // Pre-set the client if provided (blocking set is fine during construction)
163	                cell.set(Arc::new(client)).ok();
164	                cell
165	            }
166	            None => OnceCell::new(),
167	        });
168	
169	        let healthy = true;
170	        Metrics::set_worker_health(&self.url, healthy);
171	
172	        BasicWorker {
173	            metadata,
174	            load_counter: Arc::new(AtomicUsize::new(0)),
175	            worker_routing_key_load: Arc::new(WorkerRoutingKeyLoad::new(&self.url)),
176	            processed_counter: Arc::new(AtomicUsize::new(0)),
177	            healthy: Arc::new(AtomicBool::new(healthy)),
178	            consecutive_failures: Arc::new(AtomicUsize::new(0)),
179	            consecutive_successes: Arc::new(AtomicUsize::new(0)),
180	            circuit_breaker: CircuitBreaker::with_config_and_label(
181	                self.circuit_breaker_config,
182	                self.url.clone(),
183	            ),
184	            grpc_client,
185	            models_override: Arc::new(StdRwLock::new(None)),
186	        }
187	    }
188	}
