314	    /// Build the DPAwareWorker instance
315	    pub fn build(self) -> DPAwareWorker {
316	        let worker_url = format!("{}@{}", self.base_url, self.dp_rank);
317	        let mut builder = BasicWorkerBuilder::new(worker_url)
318	            .models(self.models)
319	            .worker_type(self.worker_type)
320	            .connection_mode(self.connection_mode)
321	            .runtime_type(self.runtime_type)
322	            .labels(self.labels)
323	            .health_config(self.health_config)
324	            .circuit_breaker_config(self.circuit_breaker_config);
325	
326	        if let Some(client) = self.grpc_client {
327	            builder = builder.grpc_client(client);
328	        }
329	        if let Some(api_key) = self.api_key {
330	            builder = builder.api_key(api_key);
331	        }
332	
333	        let base_worker = builder.build();
334	        DPAwareWorker::with_base_worker(base_worker, self.base_url, self.dp_rank, self.dp_size)
335	    }
336	}
