679	impl BasicWorker {
680	    pub fn normalised_url(&self) -> WorkerResult<&str> {
681	        // Use rfind directly - no need for redundant contains() check
682	        // rfind already returns None if '@' is not found
683	        // e.g., "http://[::1]:8080@0" -> "http://[::1]:8080" and "0"
684	        if let Some(at_pos) = self.url().rfind('@') {
685	            let base_url = &self.url()[..at_pos];
686	            let rank_str = &self.url()[at_pos + 1..];
687	
688	            // Validate that the rank part is actually a number
689	            if rank_str.parse::<usize>().is_ok() {
690	                Ok(base_url)
691	            } else {
692	                // The '@' is not a DP rank separator, return full URL
693	                Ok(self.url())
694	            }
695	        } else {
696	            Ok(self.url())
697	        }
698	    }
