706	#[async_trait]
707	impl Worker for BasicWorker {
708	    fn url(&self) -> &str {
709	        &self.metadata.url
710	    }
711	
712	    fn api_key(&self) -> &Option<String> {
713	        &self.metadata.api_key
714	    }
715	
716	    fn worker_type(&self) -> &WorkerType {
717	        &self.metadata.worker_type
718	    }
719	
720	    fn connection_mode(&self) -> &ConnectionMode {
721	        &self.metadata.connection_mode
722	    }
723	
724	    fn is_healthy(&self) -> bool {
725	        self.healthy.load(Ordering::Acquire)
726	    }
727	
728	    fn set_healthy(&self, healthy: bool) {
729	        self.healthy.store(healthy, Ordering::Release);
730	        Metrics::set_worker_health(self.url(), healthy);
731	    }
732	
733	    async fn check_health_async(&self) -> WorkerResult<()> {
734	        if self.metadata.health_config.disable_health_check {
735	            if !self.is_healthy() {
736	                self.set_healthy(true);
737	            }
738	            return Ok(());
739	        }
740	
741	        let health_result = match &self.metadata.connection_mode {
742	            ConnectionMode::Http => self.http_health_check().await?,
743	            ConnectionMode::Grpc { .. } => self.grpc_health_check().await?,
744	        };
745	
746	        // Get worker type label for metrics
747	        let worker_type_str = self.metadata.worker_type.as_metric_label();
748	
749	        if health_result {
750	            self.consecutive_failures.store(0, Ordering::Release);
751	            let successes = self.consecutive_successes.fetch_add(1, Ordering::AcqRel) + 1;
752	
753	            // Record health check success metric
754	            Metrics::record_worker_health_check(worker_type_str, metrics_labels::CB_SUCCESS);
755	
756	            if !self.is_healthy()
757	                && successes >= self.metadata.health_config.success_threshold as usize
758	            {
759	                self.set_healthy(true);
760	                self.consecutive_successes.store(0, Ordering::Release);
761	            }
762	            Ok(())
763	        } else {
764	            self.consecutive_successes.store(0, Ordering::Release);
765	            let failures = self.consecutive_failures.fetch_add(1, Ordering::AcqRel) + 1;
766	
767	            // Record health check failure metric
768	            Metrics::record_worker_health_check(worker_type_str, metrics_labels::CB_FAILURE);
769	
770	            if self.is_healthy()
771	                && failures >= self.metadata.health_config.failure_threshold as usize
772	            {
773	                self.set_healthy(false);
774	                self.consecutive_failures.store(0, Ordering::Release);
775	            }
776	
777	            Err(WorkerError::HealthCheckFailed {
778	                url: self.metadata.url.clone(),
779	                reason: format!("Health check failed (consecutive failures: {})", failures),
780	            })
781	        }
782	    }
783	
784	    fn load(&self) -> usize {
785	        self.load_counter.load(Ordering::Relaxed)
786	    }
787	
788	    fn increment_load(&self) {
789	        self.load_counter.fetch_add(1, Ordering::Relaxed);
790	        self.update_running_requests_metrics();
791	    }
792	
793	    fn decrement_load(&self) {
794	        if self
795	            .load_counter
796	            .fetch_update(Ordering::Relaxed, Ordering::Relaxed, |current| {
797	                current.checked_sub(1)
798	            })
799	            .is_err()
800	        {
801	            tracing::warn!(
802	                worker_url = %self.metadata.url,
803	                "Attempted to decrement load counter that is already at 0"
804	            );
805	        }
806	        self.update_running_requests_metrics();
807	    }
808	
809	    fn reset_load(&self) {
810	        self.load_counter.store(0, Ordering::Relaxed);
811	        self.update_running_requests_metrics();
812	    }
813	
814	    fn worker_routing_key_load(&self) -> &WorkerRoutingKeyLoad {
815	        &self.worker_routing_key_load
816	    }
817	
818	    fn processed_requests(&self) -> usize {
819	        self.processed_counter.load(Ordering::Relaxed)
820	    }
821	
822	    fn increment_processed(&self) {
823	        self.processed_counter.fetch_add(1, Ordering::Relaxed);
824	    }
825	
826	    fn metadata(&self) -> &WorkerMetadata {
827	        &self.metadata
828	    }
829	
830	    fn circuit_breaker(&self) -> &CircuitBreaker {
831	        &self.circuit_breaker
832	    }
833	
834	    fn supports_model(&self, model_id: &str) -> bool {
835	        // Check models_override first (for lazy discovery)
836	        if let Ok(guard) = self.models_override.read() {
837	            if let Some(ref models) = *guard {
838	                // Models were discovered - check if this model is supported
839	                return models.iter().any(|m| m.matches(model_id));
840	            }
841	        }
842	        // Fall back to metadata.models (empty = wildcard = supports nothing until discovery)
843	        self.metadata.supports_model(model_id)
844	    }
845	
846	    fn set_models(&self, models: Vec<ModelCard>) {
847	        if let Ok(mut guard) = self.models_override.write() {
848	            tracing::debug!(
849	                "Setting {} models for worker {} via lazy discovery",
850	                models.len(),
851	                self.metadata.url
852	            );
853	            *guard = Some(models);
854	        }
855	    }
856	
857	    fn has_models_discovered(&self) -> bool {
858	        // Check if models_override has been set
859	        if let Ok(guard) = self.models_override.read() {
860	            if guard.is_some() {
861	                return true;
862	            }
863	        }
864	        // Fall back to checking metadata.models
865	        !self.metadata.models.is_empty()
866	    }
867	
868	    async fn get_grpc_client(&self) -> WorkerResult<Option<Arc<GrpcClient>>> {
869	        match self.metadata.connection_mode {
870	            ConnectionMode::Http => Ok(None),
871	            ConnectionMode::Grpc { .. } => {
872	                // OnceCell provides lock-free reads after initialization.
873	                // get_or_try_init only acquires internal lock on first call.
874	                let client = self
875	                    .grpc_client
876	                    .get_or_try_init(|| async {
877	                        let runtime_str = self.metadata.runtime_type.to_string();
878	                        tracing::info!(
879	                            "Lazily initializing gRPC client ({}) for worker: {}",
880	                            runtime_str,
881	                            self.metadata.url
882	                        );
883	                        match GrpcClient::connect(&self.metadata.url, &runtime_str).await {
884	                            Ok(client) => {
885	                                tracing::info!(
886	                                    "Successfully connected gRPC client ({}) for worker: {}",
887	                                    runtime_str,
888	                                    self.metadata.url
889	                                );
890	                                Ok(Arc::new(client))
891	                            }
892	                            Err(e) => {
893	                                tracing::error!(
894	                                    "Failed to connect gRPC client for worker {}: {}",
895	                                    self.metadata.url,
896	                                    e
897	                                );
898	                                Err(WorkerError::ConnectionFailed {
899	                                    url: self.metadata.url.clone(),
900	                                    reason: format!("Failed to connect to gRPC server: {}", e),
901	                                })
902	                            }
903	                        }
904	                    })
905	                    .await?;
906	                Ok(Some(Arc::clone(client)))
907	            }
908	        }
909	    }
910	
911	    async fn reset_grpc_client(&self) -> WorkerResult<()> {
912	        // OnceCell doesn't support resetting. This is intentional for lock-free performance.
913	        // If a connection fails, the worker should be removed and re-added.
914	        tracing::debug!(
915	            "reset_grpc_client called for {} (no-op with OnceCell)",
916	            self.metadata.url
917	        );
918	        Ok(())
919	    }
920	
921	    async fn grpc_health_check(&self) -> WorkerResult<bool> {
922	        let timeout = Duration::from_secs(self.metadata.health_config.timeout_secs);
923	        let maybe = self.get_grpc_client().await?;
924	        let Some(grpc_client) = maybe else {
925	            tracing::error!(
926	                "Worker {} is not a gRPC worker but connection mode is gRPC",
927	                self.metadata.url
928	            );
929	            return Ok(false);
930	        };
931	
932	        match time::timeout(timeout, grpc_client.health_check()).await {
933	            Ok(Ok(resp)) => {
934	                tracing::debug!(
935	                    "gRPC health OK for {}: healthy={}",
936	                    self.metadata.url,
937	                    resp.healthy
938	                );
939	                Ok(resp.healthy)
940	            }
941	            Ok(Err(err)) => {
942	                tracing::warn!("gRPC health RPC error for {}: {err:?}", self.metadata.url);
943	                Ok(false)
944	            }
945	            Err(_) => {
946	                tracing::warn!("gRPC health timed out for {}", self.metadata.url);
947	                Ok(false)
948	            }
949	        }
950	    }
951	
952	    async fn http_health_check(&self) -> WorkerResult<bool> {
953	        let timeout = Duration::from_secs(self.metadata.health_config.timeout_secs);
954	
955	        let url = self.normalised_url()?;
956	        let health_url = format!("{}{}", url, self.metadata.health_config.endpoint);
957	
958	        let mut req = WORKER_CLIENT.get(&health_url).timeout(timeout);
959	        if let Some(api_key) = &self.metadata.api_key {
960	            req = req.bearer_auth(api_key);
961	        }
962	
963	        match req.send().await {
964	            Ok(resp) => {
965	                let status = resp.status();
966	                if status.is_success() {
967	                    Ok(true)
968	                } else {
969	                    tracing::warn!(
970	                        "HTTP health check returned non-success status for {}: {}",
971	                        health_url,
972	                        status
973	                    );
974	                    Ok(false)
975	                }
976	            }
977	            Err(err) => {
978	                tracing::warn!("HTTP health check failed for {}: {err:?}", health_url);
979	                Ok(false)
980	            }
981	        }
982	    }
983	}
