1180	/// Body wrapper that holds an attached value.
1181	///
1182	/// When this body is dropped (stream ends or client disconnects),
1183	/// the attached value is dropped automatically. This is useful for RAII guards
1184	/// like WorkerLoadGuard that need to be tied to a response body's lifetime.
1185	pub struct AttachedBody<T> {
1186	    inner: Body,
1187	    _attached: T,
1188	}
1189	
1190	impl<T> AttachedBody<T> {
1191	    pub fn new(inner: Body, attached: T) -> Self {
1192	        Self {
1193	            inner,
1194	            _attached: attached,
1195	        }
1196	    }
1197	}
1198	
1199	impl<T: Send + Unpin + 'static> AttachedBody<T> {
1200	    pub fn wrap_response(
1201	        response: axum::response::Response,
1202	        attached: T,
1203	    ) -> axum::response::Response {
1204	        let (parts, body) = response.into_parts();
1205	        axum::response::Response::from_parts(parts, Body::new(Self::new(body, attached)))
1206	    }
1207	}
