1209	impl<T: Send + Unpin + 'static> http_body::Body for AttachedBody<T> {
1210	    type Data = bytes::Bytes;
1211	    type Error = axum::Error;
1212	
1213	    fn poll_frame(
1214	        self: std::pin::Pin<&mut Self>,
1215	        cx: &mut std::task::Context<'_>,
1216	    ) -> std::task::Poll<Option<Result<http_body::Frame<Self::Data>, Self::Error>>> {
1217	        let this = self.get_mut();
1218	        std::pin::Pin::new(&mut this.inner).poll_frame(cx)
1219	    }
1220	
1221	    fn is_end_stream(&self) -> bool {
1222	        self.inner.is_end_stream()
1223	    }
1224	
1225	    fn size_hint(&self) -> http_body::SizeHint {
1226	        self.inner.size_hint()
1227	    }
1228	}
