1	//! Model type definitions using bitflags for endpoint support.
2	//!
3	//! This module defines [`ModelType`] using bitflags to represent which endpoints
4	//! a model can support. This allows combining capabilities like
5	//! `ModelType::CHAT | ModelType::COMPLETIONS`.
6	//!
7	//! Inspired by Dynamo's model_type.rs implementation.
8	
9	use bitflags::bitflags;
10	use serde::{Deserialize, Serialize};
11	
12	bitflags! {
13	    #[derive(Copy, Debug, Default, Clone, Eq, PartialEq, Hash)]
14	    pub struct ModelType: u16 {
15	        /// OpenAI Chat Completions API (/v1/chat/completions)
16	        const CHAT        = 1 << 0;
17	        /// OpenAI Completions API - legacy (/v1/completions)
18	        const COMPLETIONS = 1 << 1;
19	        /// OpenAI Responses API (/v1/responses)
20	        const RESPONSES   = 1 << 2;
21	        /// Embeddings API (/v1/embeddings)
22	        const EMBEDDINGS  = 1 << 3;
23	        /// Rerank API (/v1/rerank)
24	        const RERANK      = 1 << 4;
25	        /// SGLang Generate API (/generate)
26	        const GENERATE    = 1 << 5;
27	        /// Vision/multimodal support (images in input)
28	        const VISION      = 1 << 6;
29	        /// Tool/function calling support
30	        const TOOLS       = 1 << 7;
31	        /// Reasoning/thinking support (e.g., o1, DeepSeek-R1)
32	        const REASONING   = 1 << 8;
33	        /// Image generation (DALL-E, Sora, gpt-image)
34	        const IMAGE_GEN   = 1 << 9;
35	        /// Audio models (TTS, Whisper, realtime, transcribe)
36	        const AUDIO       = 1 << 10;
37	        /// Content moderation models
38	        const MODERATION  = 1 << 11;
39	
40	        /// Standard LLM: chat + completions + responses + tools
41	        const LLM = Self::CHAT.bits() | Self::COMPLETIONS.bits()
42	                  | Self::RESPONSES.bits() | Self::TOOLS.bits();
43	
44	        /// Vision-capable LLM: LLM + vision
45	        const VISION_LLM = Self::LLM.bits() | Self::VISION.bits();
46	
47	        /// Reasoning LLM: LLM + reasoning (e.g., o1, o3, DeepSeek-R1)
48	        const REASONING_LLM = Self::LLM.bits() | Self::REASONING.bits();
49	
50	        /// Full-featured LLM: all text generation capabilities
51	        const FULL_LLM = Self::VISION_LLM.bits() | Self::REASONING.bits();
52	
53	        /// Embedding model only
54	        const EMBED_MODEL = Self::EMBEDDINGS.bits();
55	
56	        /// Reranker model only
57	        const RERANK_MODEL = Self::RERANK.bits();
58	
59	        /// Image generation model only (DALL-E, Sora, gpt-image)
60	        const IMAGE_MODEL = Self::IMAGE_GEN.bits();
61	
62	        /// Audio model only (TTS, Whisper, realtime)
63	        const AUDIO_MODEL = Self::AUDIO.bits();
64	
65	        /// Content moderation model only
66	        const MODERATION_MODEL = Self::MODERATION.bits();
67	    }
68	}
69	
70	/// Mapping of individual capability flags to their names.
71	/// Used by `as_capability_names()` for a data-driven approach.
72	const CAPABILITY_NAMES: &[(ModelType, &str)] = &[
73	    (ModelType::CHAT, "chat"),
74	    (ModelType::COMPLETIONS, "completions"),
75	    (ModelType::RESPONSES, "responses"),
76	    (ModelType::EMBEDDINGS, "embeddings"),
77	    (ModelType::RERANK, "rerank"),
78	    (ModelType::GENERATE, "generate"),
79	    (ModelType::VISION, "vision"),
80	    (ModelType::TOOLS, "tools"),
81	    (ModelType::REASONING, "reasoning"),
82	    (ModelType::IMAGE_GEN, "image_gen"),
83	    (ModelType::AUDIO, "audio"),
84	    (ModelType::MODERATION, "moderation"),
85	];
86	
87	impl ModelType {
88	    /// Check if this model type supports the chat completions endpoint
89	    #[inline]
90	    pub fn supports_chat(&self) -> bool {
91	        self.contains(Self::CHAT)
92	    }
93	
94	    /// Check if this model type supports the legacy completions endpoint
95	    #[inline]
96	    pub fn supports_completions(&self) -> bool {
97	        self.contains(Self::COMPLETIONS)
98	    }
99	
100	    /// Check if this model type supports the responses endpoint
101	    #[inline]
102	    pub fn supports_responses(&self) -> bool {
103	        self.contains(Self::RESPONSES)
104	    }
105	
106	    /// Check if this model type supports the embeddings endpoint
107	    #[inline]
108	    pub fn supports_embeddings(&self) -> bool {
109	        self.contains(Self::EMBEDDINGS)
110	    }
111	
112	    /// Check if this model type supports the rerank endpoint
113	    #[inline]
114	    pub fn supports_rerank(&self) -> bool {
115	        self.contains(Self::RERANK)
116	    }
117	
118	    /// Check if this model type supports the generate endpoint
119	    #[inline]
120	    pub fn supports_generate(&self) -> bool {
121	        self.contains(Self::GENERATE)
122	    }
123	
124	    /// Check if this model type supports vision/multimodal input
125	    #[inline]
126	    pub fn supports_vision(&self) -> bool {
127	        self.contains(Self::VISION)
128	    }
129	
130	    /// Check if this model type supports tool/function calling
131	    #[inline]
132	    pub fn supports_tools(&self) -> bool {
133	        self.contains(Self::TOOLS)
134	    }
135	
136	    /// Check if this model type supports reasoning/thinking
137	    #[inline]
138	    pub fn supports_reasoning(&self) -> bool {
139	        self.contains(Self::REASONING)
140	    }
141	
142	    /// Check if this model type supports image generation
143	    #[inline]
144	    pub fn supports_image_gen(&self) -> bool {
145	        self.contains(Self::IMAGE_GEN)
146	    }
147	
148	    /// Check if this model type supports audio (TTS, Whisper, etc.)
149	    #[inline]
150	    pub fn supports_audio(&self) -> bool {
151	        self.contains(Self::AUDIO)
152	    }
153	
154	    /// Check if this model type supports content moderation
155	    #[inline]
156	    pub fn supports_moderation(&self) -> bool {
157	        self.contains(Self::MODERATION)
158	    }
159	
160	    /// Check if this model type supports a given endpoint
161	    pub fn supports_endpoint(&self, endpoint: Endpoint) -> bool {
162	        match endpoint {
163	            Endpoint::Chat => self.supports_chat(),
164	            Endpoint::Completions => self.supports_completions(),
165	            Endpoint::Responses => self.supports_responses(),
166	            Endpoint::Embeddings => self.supports_embeddings(),
167	            Endpoint::Rerank => self.supports_rerank(),
168	            Endpoint::Generate => self.supports_generate(),
169	            Endpoint::Models => true, // Models endpoint is always supported
170	        }
171	    }
172	
173	    /// Convert to a list of supported capability names
174	    pub fn as_capability_names(&self) -> Vec<&'static str> {
175	        let mut result = Vec::with_capacity(CAPABILITY_NAMES.len());
176	        for &(flag, name) in CAPABILITY_NAMES {
177	            if self.contains(flag) {
178	                result.push(name);
179	            }
