1	//! Model card definitions for worker model configuration.
2	//!
3	//! This module defines [`ModelCard`] which consolidates model-related configuration
4	//! that was previously scattered in `WorkerMetadata.labels` HashMap.
5	//!
6	//! Also defines [`ProviderType`] for vendor-specific API transformations.
7	//!
8	//! Inspired by Dynamo's ModelDeploymentCard but simplified for router needs.
9	
10	use std::collections::HashMap;
11	
12	use serde::{Deserialize, Serialize};
13	
14	use super::{
15	    model_type::{Endpoint, ModelType},
16	    UNKNOWN_MODEL_ID,
17	};
18	
19	/// Provider type for external API transformations.
20	///
21	/// Different providers have different API formats and requirements.
22	/// This enum identifies which vendor's API format to use for transformations.
23	///
24	/// Note: `None` (when used as `Option<ProviderType>`) means native/passthrough -
25	/// no transformation needed. This is the case for local SGLang backends.
26	#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
27	#[serde(rename_all = "lowercase")]
28	pub enum ProviderType {
29	    /// OpenAI API - strip SGLang-specific fields
30	    #[serde(alias = "openai")]
31	    OpenAI,
32	    /// xAI/Grok - special handling for input items
33	    #[serde(alias = "xai", alias = "grok")]
34	    XAI,
35	    /// Anthropic Claude - different API format
36	    #[serde(alias = "anthropic", alias = "claude")]
37	    Anthropic,
38	    /// Google Gemini - special logprobs handling
39	    #[serde(alias = "gemini", alias = "google")]
40	    Gemini,
41	    /// Custom provider with string identifier
42	    #[serde(untagged)]
43	    Custom(String),
44	}
45	
46	impl ProviderType {
47	    /// Get provider name as string
48	    pub fn as_str(&self) -> &str {
49	        match self {
50	            Self::OpenAI => "openai",
51	            Self::XAI => "xai",
52	            Self::Anthropic => "anthropic",
53	            Self::Gemini => "gemini",
54	            Self::Custom(s) => s.as_str(),
55	        }
56	    }
57	
58	    /// Detect provider from model name (heuristic fallback).
59	    /// Returns `None` for models that don't match known external providers
60	    /// (i.e., models served by local/native backends).
61	    pub fn from_model_name(model: &str) -> Option<Self> {
62	        let model_lower = model.to_lowercase();
63	        if model_lower.starts_with("grok") {
64	            Some(Self::XAI)
65	        } else if model_lower.starts_with("gemini") {
66	            Some(Self::Gemini)
67	        } else if model_lower.starts_with("claude") {
68	            Some(Self::Anthropic)
69	        } else if model_lower.starts_with("gpt")
70	            || model_lower.starts_with("o1")
71	            || model_lower.starts_with("o3")
72	        {
73	            Some(Self::OpenAI)
74	        } else {
75	            None // Native/local model, no provider transformation needed
76	        }
77	    }
78	}
79	
80	impl std::fmt::Display for ProviderType {
81	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
82	        write!(f, "{}", self.as_str())
83	    }
84	}
85	
86	/// Model card containing model configuration and capabilities.
87	///
88	/// Consolidates fields previously scattered in `WorkerMetadata.labels`:
89	/// - `model_id` -> `id`
90	/// - `tokenizer_path` -> `tokenizer_path`
91	/// - `chat_template` -> `chat_template`
92	/// - `reasoning_parser` -> `reasoning_parser`
93	/// - `tool_parser` -> `tool_parser`
94	///
95	/// # Example
96	///
97	/// ```
98	/// use smg::core::{model_type::ModelType, ModelCard, ProviderType};
99	///
100	/// let card = ModelCard::new("meta-llama/Llama-3.1-8B-Instruct")
101	///     .with_display_name("Llama 3.1 8B Instruct")
102	///     .with_alias("llama-3.1-8b")
103	///     .with_model_type(ModelType::VISION_LLM)
104	///     .with_context_length(128_000)
105	///     .with_tokenizer_path("meta-llama/Llama-3.1-8B-Instruct");
106	///
107	/// assert!(card.matches("llama-3.1-8b"));
108	/// assert!(card.model_type.supports_vision());
109	/// assert!(card.provider.is_none()); // Local model, no external provider
110	/// ```
111	#[derive(Debug, Clone, Serialize, Deserialize)]
112	pub struct ModelCard {
113	    // === Identity ===
114	    /// Primary model ID (e.g., "meta-llama/Llama-3.1-8B-Instruct")
115	    /// Previously: labels.get("model_id")
116	    pub id: String,
117	
118	    /// Optional display name (e.g., "Llama 3.1 8B Instruct")
119	    #[serde(default, skip_serializing_if = "Option::is_none")]
120	    pub display_name: Option<String>,
121	
122	    /// Alternative names/aliases for this model
123	    #[serde(default, skip_serializing_if = "Vec::is_empty")]
124	    pub aliases: Vec<String>,
125	
126	    // === Capabilities ===
127	    /// Supported endpoint types (bitflags)
128	    #[serde(default = "default_model_type")]
129	    pub model_type: ModelType,
130	
131	    /// HuggingFace model type string (e.g., "llama", "qwen2", "gpt-oss")
132	    /// This is different from `model_type` which is capability bitflags.
133	    #[serde(default, skip_serializing_if = "Option::is_none")]
134	    pub hf_model_type: Option<String>,
135	
136	    /// Model architectures from HuggingFace config (e.g., ["LlamaForCausalLM"])
137	    #[serde(default, skip_serializing_if = "Vec::is_empty")]
138	    pub architectures: Vec<String>,
139	
140	    /// Provider hint for API transformations.
141	    /// `None` means native/passthrough (no transformation needed).
142	    #[serde(default, skip_serializing_if = "Option::is_none")]
143	    pub provider: Option<ProviderType>,
144	
145	    /// Maximum context length in tokens
146	    #[serde(default, skip_serializing_if = "Option::is_none")]
147	    pub context_length: Option<u32>,
148	
149	    // === Tokenization & Parsing (previously in labels) ===
150	    /// Path to tokenizer (e.g., HuggingFace model ID or local path)
151	    /// Previously: labels.get("tokenizer_path")
152	    #[serde(default, skip_serializing_if = "Option::is_none")]
153	    pub tokenizer_path: Option<String>,
154	
155	    /// Chat template (Jinja2 template string or path)
156	    /// Previously: labels.get("chat_template")
157	    #[serde(default, skip_serializing_if = "Option::is_none")]
158	    pub chat_template: Option<String>,
159	
160	    /// Reasoning parser type (e.g., "deepseek", "qwen")
161	    /// Previously: labels.get("reasoning_parser")
162	    #[serde(default, skip_serializing_if = "Option::is_none")]
163	    pub reasoning_parser: Option<String>,
164	
165	    /// Tool/function calling parser type (e.g., "llama", "mistral")
166	    /// Previously: labels.get("tool_parser")
167	    #[serde(default, skip_serializing_if = "Option::is_none")]
168	    pub tool_parser: Option<String>,
169	
170	    /// User-defined metadata (for fields not covered above)
171	    #[serde(default, skip_serializing_if = "Option::is_none")]
172	    pub metadata: Option<serde_json::Value>,
173	
174	    // === Classification Support ===
175	    /// Classification label mapping (class index -> label name).
176	    /// Empty if not a classification model.
177	    /// Example: {0: "negative", 1: "positive"}
